const scoreText = $input.first().json.message?.content || '{}';
let scoring;
try {
  const match = scoreText.match(/\{[\s\S]*\}/);
  scoring = JSON.parse(match ? match[0] : scoreText);
} catch {
  scoring = { score: 50, tier: 'warm', reasoning: 'Unable to parse', personalization_angle: '' };
}

const lead = $('Parse Lead Data').first().json;

return [{
  json: {
    ...lead,
    icpScore: scoring.score || 50,
    tier: scoring.tier || 'warm',
    reasoning: scoring.reasoning || '',
    personalizationAngle: scoring.personalization_angle || ''
  }
}];

